def select_model_for_task(task_type: str, data_classification: str, needs_tools: bool) -> str:
    """Query the registry to find the best approved model for the task."""
    params = {
        "type": "chat-completion",
        "status_filter": "active",
        "max_data_classification": data_classification,
    }
    if needs_tools:
        params["tool_calling"] = True

    resp = httpx.get(
        f"{REGISTRY_BASE}/models",
        params=params,
        headers={"Authorization": f"Bearer {get_registry_token()}"}
    )
    candidates = resp.json()

    # Sort by cost (cheapest first) for non-critical tasks
    candidates.sort(key=lambda m: m["registration"]["cost_input_per_1k"])
    if not candidates:
        raise RuntimeError(f"No approved model found for {task_type} with {data_classification} data")
    return candidates[0]["id"]
